#!/usr/bin/env python3
import argparse
from pathlib import Path

TEMPLATE = """
// AUTO-GENERATED by gen_microbench.py

target C {{
}}

preamble {{=
#include <stdlib.h>
#include "core/reactor.h"
#include <inttypes.h>
#include <stdarg.h>
#include <stdio.h>
#include <time.h>

static FILE* ms_eval_log_fp = NULL;
static int ms_eval_log_opened = 0;

static int64_t ms_eval_now_mono_ns(void) {{
  struct timespec ts;
  clock_gettime(CLOCK_MONOTONIC, &ts);
  return (int64_t)ts.tv_sec * 1000000000LL + (int64_t)ts.tv_nsec;
}}

static void ms_eval_log_printf(const char* fmt, ...) {{
  if (ms_eval_log_fp == NULL) return;
  va_list args;
  va_start(args, fmt);
  vfprintf(ms_eval_log_fp, fmt, args);
  va_end(args);
  fputc('\\n', ms_eval_log_fp);
  fflush(ms_eval_log_fp);
}}

static void ms_eval_log_init(const char* log_path,
                      const char* experiment,
                      const char* mode,
                      int reactions,
                      int steps,
                      int workload_us,
                      int deadline_us,
                      double load_factor,
                      int seed) {{
  if (ms_eval_log_opened) return;
  ms_eval_log_opened = 1;
  if (log_path == NULL || log_path[0] == '\\0') return;
  ms_eval_log_fp = fopen(log_path, "a");
  if (ms_eval_log_fp == NULL) return;
  ms_eval_log_printf(
      "{{\\"type\\":\\"run_start\\",\\"ts_mono_ns\\":%" PRId64
      ",\\"experiment\\":\\"%s\\",\\"mode\\":\\"%s\\",\\"reactions\\":%d,"
      "\\"steps\\":%d,\\"workload_us\\":%d,\\"deadline_us\\":%d,"
      "\\"load_factor\\":%.3f,\\"seed\\":%d}}",
      ms_eval_now_mono_ns(),
      (experiment != NULL ? experiment : ""),
      (mode != NULL ? mode : ""),
      reactions,
      steps,
      workload_us,
      deadline_us,
      load_factor,
      seed);
}}

static void ms_eval_log_reaction_start(int reaction_id,
                                int64_t logical_time_ns,
                                int64_t physical_time_ns) {{
  ms_eval_log_printf(
      "{{\\"type\\":\\"reaction_start\\",\\"ts_mono_ns\\":%" PRId64
      ",\\"logical_time_ns\\":%" PRId64 ",\\"reaction_id\\":%d}}",
      physical_time_ns,
      logical_time_ns,
      reaction_id);
}}

static void ms_eval_log_reaction_end(int reaction_id,
                              int64_t logical_time_ns,
                              int64_t physical_time_ns,
                              int64_t deadline_us,
                              int missed_deadline) {{
  ms_eval_log_printf(
      "{{\\"type\\":\\"reaction_end\\",\\"ts_mono_ns\\":%" PRId64
      ",\\"logical_time_ns\\":%" PRId64 ",\\"reaction_id\\":%d,"
      "\\"deadline_us\\":%" PRId64 ",\\"missed_deadline\\":%d}}",
      physical_time_ns,
      logical_time_ns,
      reaction_id,
      deadline_us,
      missed_deadline);
}}

static void ms_eval_log_injection(int reaction_id,
                           int64_t logical_time_ns,
                           int injected_delay_us,
                           int deadline_us,
                           int expected_miss) {{
  ms_eval_log_printf(
      "{{\\"type\\":\\"injection\\",\\"ts_mono_ns\\":%" PRId64
      ",\\"logical_time_ns\\":%" PRId64 ",\\"reaction_id\\":%d,"
      "\\"injected_delay_us\\":%d,\\"deadline_us\\":%d,\\"expected_miss\\":%d}}",
      ms_eval_now_mono_ns(),
      logical_time_ns,
      reaction_id,
      injected_delay_us,
      deadline_us,
      expected_miss);
}}

static void ms_eval_busy_wait_us(int work_us) {{
  if (work_us <= 0) return;
  int64_t start = ms_eval_now_mono_ns();
  int64_t target = start + (int64_t)work_us * 1000LL;
  while (ms_eval_now_mono_ns() < target) {{
  }}
}}

static uint64_t ms_eval_hash_u64(uint64_t x) {{
  x ^= x >> 33;
  x *= 0xff51afd7ed558ccdULL;
  x ^= x >> 33;
  x *= 0xc4ceb9fe1a85ec53ULL;
  x ^= x >> 33;
  return x;
}}

static int ms_eval_should_inject(int reaction_id,
                          int64_t logical_time_ns,
                          int inject_period,
                          int inject_rate_pct) {{
  if (inject_period <= 0 || inject_rate_pct <= 0) return 0;
  if ((logical_time_ns / 1000LL) % inject_period != 0) return 0;
  uint64_t seed = ((uint64_t)reaction_id << 32) ^ (uint64_t)logical_time_ns;
  uint64_t h = ms_eval_hash_u64(seed);
  int bucket = (int)(h % 100ULL);
  return bucket < inject_rate_pct;
}}

static int ms_eval_inject_period = 0;
static int ms_eval_inject_rate = 0;
static int ms_eval_inject_delay_us = 0;
static int ms_eval_deadline_us = {deadline_us};
static int ms_eval_steps = {steps};
static int ms_eval_workload_us = {workload_us};
static int ms_eval_seed = {seed};

static int ms_eval_get_env_int(const char* key, int fallback) {{
  const char* v = getenv(key);
  return v ? atoi(v) : fallback;
}}
=}}

main reactor {{
  timer t(0, {period_us} us);
  state step:int = 0;

  reaction(startup) {{=
    ms_eval_inject_period = ms_eval_get_env_int("MS_EVAL_INJECT_PERIOD", 0);
    ms_eval_inject_rate = ms_eval_get_env_int("MS_EVAL_INJECT_RATE_PCT", 0);
    ms_eval_inject_delay_us = ms_eval_get_env_int("MS_EVAL_INJECT_DELAY_US", 0);
    const char* log_path = getenv("LF_APP_LOG");
    const char* mode = getenv("MS_MODE");
    ms_eval_log_init(log_path, "{experiment}", mode, {reactions}, ms_eval_steps,
                     ms_eval_workload_us, ms_eval_deadline_us, 1.0, ms_eval_seed);
  =}}

{reactions_block}
}}
"""

REACTION_TEMPLATE = """
  reaction(t) {{=
    const int reaction_id = {rid};
    int64_t logical = (int64_t)lf_time_logical();
    int64_t physical = (int64_t)lf_time_physical();
    int inject = ms_eval_should_inject(reaction_id, logical,
                                       ms_eval_inject_period, ms_eval_inject_rate);
    if (inject) {{
      ms_eval_log_injection(reaction_id, logical, ms_eval_inject_delay_us,
                            ms_eval_deadline_us, (ms_eval_inject_delay_us > ms_eval_deadline_us));
    }}
    ms_eval_log_reaction_start(reaction_id, logical, physical);
    ms_eval_busy_wait_us(ms_eval_workload_us + (inject ? ms_eval_inject_delay_us : 0));
    int64_t physical_end = (int64_t)lf_time_physical();
    int missed = (ms_eval_deadline_us > 0 &&
                  physical_end > logical + (int64_t)ms_eval_deadline_us * 1000LL);
    ms_eval_log_reaction_end(reaction_id, logical, physical_end, ms_eval_deadline_us, missed);
    {step_logic}
  =}}
"""


def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument("--out", required=True)
    ap.add_argument("--reactions", type=int, required=True)
    ap.add_argument("--workload-us", type=int, required=True)
    ap.add_argument("--deadline-us", type=int, required=True)
    ap.add_argument("--period-us", type=int, default=1000)
    ap.add_argument("--steps", type=int, default=1000)
    ap.add_argument("--seed", type=int, default=1)
    ap.add_argument("--experiment", default="e1")
    args = ap.parse_args()

    reactions = []
    for rid in range(args.reactions):
        step_logic = ""
        if rid == 0:
            step_logic = "self->step++; if (self->step >= ms_eval_steps) lf_request_stop();"
        reactions.append(REACTION_TEMPLATE.format(rid=rid, step_logic=step_logic))

    out_path = Path(args.out)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    out_path.write_text(
        TEMPLATE.format(
            reactions=args.reactions,
            steps=args.steps,
            workload_us=args.workload_us,
            deadline_us=args.deadline_us,
            period_us=args.period_us,
            seed=args.seed,
            experiment=args.experiment,
            reactions_block="\n".join(reactions),
        )
    )


if __name__ == "__main__":
    main()
